import java.io.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int read() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len == -1) return -1;
            }
            return buffer[ptr++];
        }
        Long nextLong() throws IOException {
            int c;
            do {
                c = read();
                if (c == -1) return null;
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = read();
            }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = read();
                if (c == -1) break;
            }
            return neg ? -val : val;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        Long tLong = fs.nextLong();
        if (tLong == null) {
            System.out.print("");
            return;
        }
        int T = tLong.intValue();
        boolean invalid = false;
        for (int caseIdx = 0; caseIdx < T && !invalid; caseIdx++) {
            Long nL = fs.nextLong();
            Long mL = fs.nextLong();
            if (nL == null || mL == null) { invalid = true; break; }
            int n = nL.intValue();
            int m = mL.intValue();
            long[][] a = new long[n][m];
            for (int i = 0; i < n && !invalid; i++) {
                for (int j = 0; j < m; j++) {
                    Long val = fs.nextLong();
                    if (val == null) { invalid = true; break; }
                    a[i][j] = val;
                }
            }
            for (int i = 0; i < n && !invalid; i++) {
                for (int j = 0; j < m; j++) {
                    Long b = fs.nextLong();
                    if (b == null) { invalid = true; break; }
                    sb.append(a[i][j] + b);
                    if (j + 1 < m) sb.append(' ');
                }
                sb.append('\n');
            }
        }
        if (invalid) {
            System.out.print("");
        } else {
            System.out.print(sb.toString());
        }
    }
}

